      "expected_output": "render_calls=2\ncontainer_id=\ncontainer_class=g-recaptcha\nsitekey=new-sitekey\ntheme=light\nsize=normal\nbadge=undefined\ntabindex=0\nlanguage=\nisolated=undefined\ncallbacks=verify,expire,error\n"
    },
    {
      "input": {
        "scenario": "rerender_on_change",
        "configuration": {},
        "next_configuration": {
          "challenge_size": "invisible"
        }
      },
      "expected_output": "render_calls=2\ncontainer_id=\ncontainer_class=g-recaptcha\nsitekey=some-key\ntheme=light\nsize=invisible\nbadge=bottomright\ntabindex=0\nlanguage=undefined\nisolated=false\ncallbacks=verify,expire,error\n"
    }
  ]
}
